Using CMSIS-DSP on Cortex-M4F:
```c
#include "arm_math.h"

#define FFT_SIZE 1024
float32_t fft_input[FFT_SIZE * 2]; // interleaved real/imag
float32_t fft_output[FFT_SIZE];
arm_cfft_instance_f32 fft_inst;

void compute_fft(float32_t *samples) {
    // Prepare complex input (real samples, zero imaginary)
    for (int i = 0; i < FFT_SIZE; i++) {
        fft_input[2*i] = samples[i];     // real
        fft_input[2*i+1] = 0.0f;         // imag
    }

    // Apply window (Hanning)
    for (int i = 0; i < FFT_SIZE; i++) {
        float32_t w = 0.5f * (1.0f - cosf(2.0f * M_PI * i / (FFT_SIZE - 1)));
        fft_input[2*i] *= w;
    }

    arm_cfft_f32(&arm_cfft_sR_f32_len1024, fft_input, 0, 1); // FFT
    arm_cmplx_mag_f32(fft_input, fft_output, FFT_SIZE);       // magnitude
}
```
1024-point FFT on Cortex-M4F @ 168MHz takes ~0.3ms. Use DMA double-buffering for overlap-save. For fixed-point: use arm_cfft_q15 for lower memory and faster execution.

Second-order IIR (biquad) low-pass:
```c
// Coefficients for Butterworth LPF at fc/fs = 0.1 (e.g., 4.8kHz at 48kHz)
// Use scipy.signal.butter(2, 0.1) to compute
float32_t coeffs[5] = {
    0.02008337f,  // b0
    0.04016675f,  // b1
    0.02008337f,  // b2
    1.56101808f,  // -a1 (note: CMSIS uses negated a coefficients)
    -0.64135154f  // -a2
};
float32_t state[4] = {0}; // 2 states per biquad section

arm_biquad_casd_df1_inst_f32 filter;
arm_biquad_cascade_df1_init_f32(&filter, 1, coeffs, state);

// Process block:
arm_biquad_cascade_df1_f32(&filter, input_buf, output_buf, BLOCK_SIZE);
```
For higher order: cascade multiple biquad sections. Design with scipy, MATLAB, or Iowa Hills filter designer. Always check stability: poles must be inside unit circle.

```c
#include "arm_math.h"

#define NUM_TAPS 64
#define BLOCK_SIZE 256

float32_t fir_coeffs[NUM_TAPS]; // designed externally
float32_t fir_state[NUM_TAPS + BLOCK_SIZE - 1];
arm_fir_instance_f32 fir_inst;

void init_fir(void) {
    arm_fir_init_f32(&fir_inst, NUM_TAPS, fir_coeffs, fir_state, BLOCK_SIZE);
}

void process_block(float32_t *in, float32_t *out) {
    arm_fir_f32(&fir_inst, in, out, BLOCK_SIZE);
}
```
Design coefficients with:
```python
from scipy.signal import firwin
coeffs = firwin(64, 0.2)  # 64 taps, cutoff at 0.2*Nyquist
np.savetxt('fir_coeffs.csv', coeffs)
```
FIR advantages: always stable, linear phase, easy to design. Disadvantage: more taps needed (CPU) than IIR for same rolloff.

Double-buffer pattern for audio:
```c
#define BLOCK_SIZE 256
int16_t dma_buf[BLOCK_SIZE * 2]; // DMA fills both halves
volatile uint8_t buf_ready = 0; // 1=first half, 2=second half

void HAL_I2S_RxHalfCpltCallback(I2S_HandleTypeDef *hi2s) {
    buf_ready = 1; // first half full
}
void HAL_I2S_RxCpltCallback(I2S_HandleTypeDef *hi2s) {
    buf_ready = 2; // second half full
}

// Main loop or RTOS task:
while (1) {
    if (buf_ready) {
        int16_t *src = (buf_ready == 1) ? dma_buf : dma_buf + BLOCK_SIZE;
        process_audio(src, BLOCK_SIZE); // filter, FFT, etc.
        buf_ready = 0;
    }
}
```
Latency = BLOCK_SIZE / sample_rate. At 48kHz with 256 samples: 5.3ms latency. Use I2S for audio codec (WM8960, PCM5102) with DMA circular mode.

```c
typedef struct {
    float Kp, Ki, Kd;
    float integral;
    float prev_error;
    float output_min, output_max;
    float dt; // sample period in seconds
} PID_t;

float pid_update(PID_t *pid, float setpoint, float measurement) {
    float error = setpoint - measurement;

    // Proportional
    float P = pid->Kp * error;

    // Integral with anti-windup
    pid->integral += error * pid->dt;
    float I = pid->Ki * pid->integral;

    // Derivative (on measurement to avoid kick)
    float derivative = -(measurement - pid->prev_error) / pid->dt;
    pid->prev_error = measurement;
    float D = pid->Kd * derivative;

    // Output with clamping
    float output = P + I + D;
    if (output > pid->output_max) {
        output = pid->output_max;
        pid->integral -= error * pid->dt; // anti-windup
    } else if (output < pid->output_min) {
        output = pid->output_min;
        pid->integral -= error * pid->dt;
    }

    return output;
}
```
Tuning: Start with Kp only, then add Ki for steady-state error, then Kd for overshoot. Ziegler-Nichols method for initial values. dt must match actual sample rate.
